// ─── API ───
const MODEL_CONFIG = {
  "claude-sonnet-4-20250514": { label: "Sonnet 4", short: "S4", inputRate: 3.0 / 1e6, outputRate: 15.0 / 1e6 },
  "claude-opus-4-20250514": { label: "Opus 4", short: "O4", inputRate: 15.0 / 1e6, outputRate: 75.0 / 1e6 },
  "claude-haiku-3-5-20241022": { label: "Haiku 3.5", short: "H3.5", inputRate: 0.80 / 1e6, outputRate: 4.0 / 1e6 },
};
const DEFAULT_MODEL = "claude-sonnet-4-20250514";

const TIER_MAX_TOKENS = { SIMPLE: 2000, MEDIUM: 4000, COMPLEX: 8000, CHAIN: 12000, SPAWN: 12000, ABLATION: 4000 };

let abortController = null;
async function callAPI(systemPrompt, userPrompt, model = DEFAULT_MODEL, maxTokens = 4000) {
  abortController = new AbortController();
  const r = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST", headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ model, max_tokens: maxTokens, system: systemPrompt, messages: [{ role: "user", content: userPrompt }] }),
    signal: abortController.signal,
  });
  const d = await r.json();
  const text = d.content?.map(b => b.text || "").join("") || "";
  const inTok = d.usage?.input_tokens || 0;
  const outTok = d.usage?.output_tokens || 0;
  const stopReason = d.stop_reason || "unknown";
  const cfg = MODEL_CONFIG[model] || MODEL_CONFIG[DEFAULT_MODEL];
  return { text, inTok, outTok, cost: inTok * cfg.inputRate + outTok * cfg.outputRate, stopReason };
}

function assembleSystemPrompt(tier, excludeFile) {
  const files = TIER_FILES[tier] || [];
  return files.filter(f => f !== excludeFile).map(f => `--- ${f} ---\n${CF[f] || ""}`).join("\n\n");
}

function gradeOutput(assignedTier, output) {
  if (!output || output.length < 20) return { results: [], passed: 0, total: 0, score: 0, note: "Empty/error response" };

  // ─── Detect and subtype clarification responses ───
  const verdictMeh = /Verdict.*MEH|my queen says meh|queen says meh|needs substance|I need substance|give me.*substance|too (broad|vague) to build/i.test(output);
  const verdictAlmost = /Verdict.*ALMOST|queen is interested.*but|needs more before convening|colony needs.*before|before the colony convenes|queen will hear this.*but/i.test(output);
  const verdictBeneath = /Verdict.*BENEATH|answerable.*directly|no ritual|simple.*answer|beneath the colony|doesn't need|one-line|trivial|need me to build|want me to build|shall I build|ready to build|that's it\.|that's the difference/i.test(output) && output.length < 1200 && !/TERRAIN MAP|complexity.*tier|<core_objective>|GENESIS|convene/i.test(output);
  const verdictScout = !verdictMeh && !verdictAlmost && !verdictBeneath && /clarification required|which.*targeting|before.*spawning|need to know|option [abc]:|interpretation [123]:|which matches your goal|requires clarification|needs clarification|AMBIGUOUS.*requires|before construction|missing.*information.*critical|clarification.*needed|before.*(proceed|build|construct|spawn)|What's missing|before we convene/i.test(output);

  if (verdictMeh) {
    const checks = [
      { id: "has_content", label: "Output has content", group: "messenger", pass: output.length > 30 },
      { id: "asks_domain", label: "Asks about domain", group: "messenger", pass: /what domain|what.*field|what.*area|what.*for|a prompt for what/i.test(output) },
      { id: "asks_goal", label: "Asks about goal/task", group: "messenger", pass: /what.*goal|what.*task|what.*end|what.*output|what does.*look like|what.*trying/i.test(output) },
      { id: "brief", label: "Brief (shorter than a build)", group: "messenger", pass: output.length < 1500 },
      { id: "no_premature_build", label: "Didn't build prematurely", group: "builder", pass: !/you are.*\n.*objective|<core_objective>/i.test(output) },
      { id: "specific_questions", label: "Asks specific questions (not generic)", group: "messenger", pass: /\?/.test(output) && !/tell me more|give me more details|can you elaborate/i.test(output) },
    ];
    const passed = checks.filter(r => r.pass).length;
    return { results: checks, passed, total: checks.length, score: Math.round(passed / checks.length * 100), note: "MEH — Messenger rejected: too vague", subtype: "MEH" };
  }

  if (verdictAlmost) {
    const checks = [
      { id: "has_content", label: "Output has content", group: "messenger", pass: output.length > 30 },
      { id: "acks_domain", label: "Acknowledges the domain", group: "messenger", pass: /domain|context|field|area|healthcare|trading|legal|medical|robot|drug|autonom|translat|music|climate|fraud|game|supply chain|composition|discovery|vehicle|financ|cyber|security|optim|feedback|review|ticket|code|contract|meeting|diagnosis|marketing|content|bug|menu|compet/i.test(output) },
      { id: "specific_gaps", label: "Lists specific missing info", group: "messenger", pass: /what type|what channel|what format|what output|what volume|who.*user|what.*scale|which|how many|\- .*\?/i.test(output) },
      { id: "no_generic_ask", label: "Doesn't just say 'tell me more'", group: "messenger", pass: !/^.*tell me more.*$/im.test(output) },
      { id: "brief", label: "Brief (shorter than a build)", group: "messenger", pass: output.length < 2000 },
      { id: "no_premature_build", label: "Didn't build prematurely", group: "builder", pass: !/you are.*\n.*objective|<core_objective>/i.test(output) },
    ];
    const passed = checks.filter(r => r.pass).length;
    return { results: checks, passed, total: checks.length, score: Math.round(passed / checks.length * 100), note: "ALMOST — Messenger: domain clear, details missing", subtype: "ALMOST" };
  }

  if (verdictBeneath) {
    const checks = [
      { id: "has_content", label: "Output has content", group: "messenger", pass: output.length > 20 },
      { id: "concise", label: "Concise answer (no ceremony)", group: "messenger", pass: output.length < 1000 },
      { id: "answers_directly", label: "Answers the question", group: "messenger", pass: output.length > 30 && !/what domain|what.*goal|clarification/i.test(output) },
      { id: "no_ritual", label: "No ritual invoked", group: "messenger", pass: !/TERRAIN MAP|GENESIS|Scout|Builder|Guardian|convene|complexity.*tier/i.test(output) },
      { id: "offers_next", label: "Offers next step", group: "messenger", pass: /need me to|want me to|shall I|would you like|I can.*build|ready to/i.test(output) },
    ];
    const passed = checks.filter(r => r.pass).length;
    return { results: checks, passed, total: checks.length, score: Math.round(passed / checks.length * 100), note: "BENEATH — Messenger: answered directly, no ritual", subtype: "BENEATH" };
  }

  if (verdictScout) {
    const checks = [
      { id: "has_content", label: "Output has content", group: "scout", pass: output.length > 50 },
      { id: "presents_options", label: "Presents interpretations/options", group: "scout", pass: /option|interpretation|alternative|approach|could mean|could be|version [abc123]|possibility/i.test(output) },
      { id: "concrete_examples", label: "Options have concrete examples", group: "scout", pass: /input.*→|input.*output|example|for instance|such as|e\.g\.|scenario/i.test(output) },
      { id: "asks_which", label: "Asks human to choose", group: "scout", pass: /which.*goal|which.*match|which.*prefer|which.*intent|choose|select|confirm/i.test(output) },
      { id: "domain_identified", label: "Domain identified", group: "scout", pass: /domain|context|field|area|healthcare|trading|legal|medical|robot|drug|autonom|translat|music|climate|fraud|game|supply chain|composition|discovery|vehicle|financ|cyber|security|optim|feedback|review|ticket|code|contract|meeting|diagnosis|marketing|content|bug|menu|compet/i.test(output) },
      { id: "no_premature_build", label: "Didn't build prematurely", group: "builder", pass: !/you are.*\n.*objective|<core_objective>/i.test(output) },
    ];
    const passed = checks.filter(r => r.pass).length;
    return { results: checks, passed, total: checks.length, score: Math.round(passed / checks.length * 100), note: "SCOUT — Ambiguity detected, presenting interpretations", subtype: "SCOUT" };
  }

  // ─── Detect tier escalation (colony overriding assigned tier) ───
  let effectiveTier = assignedTier;
  const tierMatch = output.match(/complexity\s*(?:tier|assessment)?:?\s*\*?\*?(SIMPLE|MEDIUM|COMPLEX|CHAIN|SPAWN)\*?\*?/i);
  if (tierMatch) {
    const detected = tierMatch[1].toUpperCase();
    const tierOrder = { SIMPLE: 0, MEDIUM: 1, COMPLEX: 2, CHAIN: 3, SPAWN: 4 };
    if (tierOrder[detected] > tierOrder[assignedTier]) {
      effectiveTier = detected; // Colony escalated — grade against its chosen tier
    }
  }

  const applicableGroups = TIER_GRADES[effectiveTier] || TIER_GRADES[assignedTier] || ["structural"];
  const results = [];
  applicableGroups.forEach(group => {
    (GRADE_CHECKS[group] || []).forEach(check => {
      results.push({ ...check, group, pass: check.test(output) });
    });
  });
  const passed = results.filter(r => r.pass).length;
  const note = effectiveTier !== assignedTier ? `Tier escalated: ${assignedTier} → ${effectiveTier} (colony override)` : null;
  return { results, passed, total: results.length, score: results.length > 0 ? Math.round(passed / results.length * 100) : 0, note };
}

// ─── LLM Quality Scoring ───
const LLM_GRADE_SYSTEM = `You are a prompt engineering quality evaluator. You will receive:
1. The original human request
2. The assigned complexity tier (SIMPLE/MEDIUM/COMPLEX/CHAIN/SPAWN)
3. The colony's complete output

Score the output 1-10 and provide structured feedback.

SCORING RUBRIC:

TIER-UNIVERSAL (all outputs):
- Does the output address what was actually asked? (not a different problem)
- Is the output specific to the domain, not generic/template-like?
- Are instructions clear and unambiguous?
- Is there appropriate use of examples?

SIMPLE (1-2 checks beyond universal):
- Is it concise? A simple prompt should be ~50-150 tokens, not bloated.
- Does it have a clear role + task + at least 1 example?

MEDIUM (adds):
- Are there constraints that prevent common failure modes?
- Is there an output format specification?
- Are there good/bad examples (70% Rule)?
- Is there validation evidence or scope definition?

COMPLEX (adds):
- Edge case handling with conditional logic?
- Multi-faceted constraints without contradiction?
- State management or context awareness?
- Adversarial/failure mode analysis?

CHAIN (adds):
- Are stages clearly separated with per-stage schemas?
- Does each stage have defined failure behavior?
- Is state management between stages explicit?
- Is the architecture diagram/flow clear?

SPAWN (adds):
- Is the hive structure complete (queen + workers + soldiers)?
- Are caste roles clearly defined with input/output schemas?
- Does the daughter hive speak the colony tongue?
- Can the daughter operate autonomously?

CLARIFICATION OUTPUTS (MEH/ALMOST/SCOUT):
- Did the colony correctly identify that the input needed clarification?
- Are the questions specific (not generic "tell me more")?
- Does it identify the domain correctly?
- Did it avoid building prematurely?

BENEATH OUTPUTS (direct answers without ritual):
- BENEATH is CORRECT colony behavior — trivial questions get answered directly, no ritual.
- Score on ANSWER QUALITY: is the answer accurate, concise, and helpful?
- Score on CONCISENESS: BENEATH answers should be short (under ~300 words). Brevity is a feature.
- Did it offer a natural next step ("Need me to build one?" / "Want me to go deeper?")?
- Do NOT penalize for: missing prompt structure, no examples, no constraints, no validation evidence. These are prompt construction criteria — BENEATH outputs are answers, not prompts.

HYPOTHESIS PROPOSALS (COMPLEX+ stopping at approach selection):
- For COMPLEX, CHAIN, and SPAWN tiers, the colony's protocol REQUIRES surfacing 2-3 architectural approaches to the human BEFORE building. This stopping point is CORRECT behavior, not a failure to build.
- Score on HYPOTHESIS QUALITY: are the proposed approaches architecturally distinct with real tradeoffs? ("Single-pass vs two-pass" is a real hypothesis. "Detailed vs simple" is not.)
- Score on DOMAIN AWARENESS: does the Scout demonstrate genuine understanding of the domain's constraints, failure modes, and design space?
- Score on TRADEOFF CLARITY: are the optimizes-for / trades-off statements specific and accurate?
- Score on SCOUT RECOMMENDATION: does the Scout provide a reasoned recommendation?
- Do NOT penalize for: not building a prompt, not delivering a finished artifact, "failing to construct," or "all reconnaissance with no construction." The colony is WAITING FOR THE HUMAN TO CHOOSE before it builds. This is by design.
- A hypothesis output that stops correctly should score 7-10 based on hypothesis quality, not 1-4 for "not building."

SCORE ANCHORS:
9-10: Production-ready. Specific, domain-aware, well-structured, good examples, handles edge cases. For hypothesis outputs: architecturally distinct approaches with genuine tradeoffs and clear domain expertise.
7-8: Solid. Addresses the request well, minor gaps in examples or edge cases. For hypothesis outputs: good approaches but tradeoffs could be sharper or domain analysis deeper.
5-6: Adequate. Correct direction but generic, missing examples, or incomplete edge case handling. For hypothesis outputs: approaches are superficially different rather than architecturally distinct.
3-4: Weak. Partially addresses request, significant gaps, template-like, missing key elements.
1-2: Failed. Wrong output type, ignores request, incoherent, or empty.

Respond ONLY with valid JSON. No markdown, no backticks, no preamble.
{
  "score": <1-10>,
  "reasoning": "<2-3 sentences explaining the score>",
  "strengths": ["<specific strength 1>", "<specific strength 2>"],
  "weaknesses": ["<specific weakness 1>", "<specific weakness 2>"],
  "is_clarification": <true if output is a clarification/question response, false if it built something>
}`;

async function llmGradeOutput(originalPrompt, tier, output, model) {
  try {
    const userMsg = `ORIGINAL REQUEST: "${originalPrompt}"
ASSIGNED TIER: ${tier}

COLONY OUTPUT:
${output.slice(0, 6000)}${output.length > 6000 ? "\n[...truncated]" : ""}

Evaluate this output now.`;

    const { text, inTok, outTok, cost } = await callAPI(LLM_GRADE_SYSTEM, userMsg, model);
    const clean = text.replace(/```json|```/g, "").trim();
    const parsed = JSON.parse(clean);
    return {
      score: Math.max(1, Math.min(10, parseInt(parsed.score) || 1)),
      reasoning: parsed.reasoning || "",
      strengths: Array.isArray(parsed.strengths) ? parsed.strengths : [],
      weaknesses: Array.isArray(parsed.weaknesses) ? parsed.weaknesses : [],
      isClarification: !!parsed.is_clarification,
      tokens: { in: inTok, out: outTok },
      cost,
    };
  } catch (err) {
    return { score: 0, reasoning: "LLM grading failed: " + err.message, strengths: [], weaknesses: [], isClarification: false, tokens: { in: 0, out: 0 }, cost: 0, error: true };
  }
}

